def solve(deps: dict[str, list[str]]) -> list[list[str]]:
    all_tasks = set(deps.keys())
    for prereqs in deps.values():
        all_tasks.update(prereqs)

    in_degree = {task: 0 for task in all_tasks}
    adjacency = {task: [] for task in all_tasks}

    for task, prereqs in deps.items():
        in_degree[task] = len(prereqs)
        for prereq in prereqs:
            adjacency[prereq].append(task)

    layers = []
    remaining = set(all_tasks)

    while remaining:
        current_layer = sorted(t for t in remaining if in_degree[t] == 0)
        if not current_layer:
            return []
        layers.append(current_layer)
        for t in current_layer:
            remaining.discard(t)
            for neighbor in adjacency[t]:
                in_degree[neighbor] -= 1

    return layers
