def solve(capacity: int, ops: list[str]) -> list[int]:
    cache = OrderedDict()
    result = []

    for op in ops:
        parts = op.split()
        if parts[0] == "put":
            if capacity == 0:
                continue
            key = int(parts[1])
            value = int(parts[2])
            if key in cache:
                cache[key] = value
                cache.move_to_end(key)
            else:
                if len(cache) >= capacity:
                    cache.popitem(last=False)
                cache[key] = value
        else:
            key = int(parts[1])
            if capacity == 0 or key not in cache:
                result.append(-1)
            else:
                cache.move_to_end(key)
                result.append(cache[key])

